use actix_web::{get, web, HttpResponse, Responder};
use crate::database::Database;
use crate::models::Invoice;

#[get("/invoices/{invoice_id}")]
pub async fn invoice_details(
    invoice_id: web::Path<String>,
    db: web::Data<Database>,
) -> impl Responder {
    let invoice_id = invoice_id.into_inner();
    let user_id = web::ext::TypedData::<UserId>::from_request().await.unwrap();

    let invoice = db
        .query_invoice_by_id_and_user_id(invoice_id, user_id)
        .await
        .unwrap();

    HttpResponse::Ok().json(invoice)
}